<?php
/**
 * ============================================
  * SGC - Configuration de la base de données (XAMPP)
   * ============================================
    */

    // Empêcher l'accès direct
    if (!defined('SGC_ACCESS')) {
        define('SGC_ACCESS', true);
        }

        // Paramètres de connexion XAMPP (par défaut)
        define('DB_HOST', 'localhost');
        define('DB_NAME', 'sgc_db');
        define('DB_USER', 'root');
        define('DB_PASS', '');          // ← XAMPP: root sans mot de passe par défaut
        define('DB_CHARSET', 'utf8mb4');

        // Options PDO
        $options = [
            PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
                PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
                    PDO::ATTR_EMULATE_PREPARES   => false,
                        PDO::MYSQL_ATTR_INIT_COMMAND => "SET NAMES " . DB_CHARSET . " COLLATE utf8mb4_unicode_ci"
                        ];

                        // Afficher les erreurs en développement
                        error_reporting(E_ALL);
                        ini_set('display_errors', '1');

                        /**
                         * Obtenir la connexion PDO
                          * @return PDO
                           */
                           function getDB(): PDO {
                               static $pdo = null;
                                   
                                       if ($pdo === null) {
                                               try {
                                                           // Vérifier si la base de données existe
                                                                       $dsn = "mysql:host=" . DB_HOST . ";charset=" . DB_CHARSET;
                                                                                   $tempPdo = new PDO($dsn, DB_USER, DB_PASS, $GLOBALS['options']);
                                                                                               
                                                                                                           // Créer la base de données si elle n'existe pas
                                                                                                                       $tempPdo->exec("CREATE DATABASE IF NOT EXISTS " . DB_NAME . " CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");
                                                                                                                                   $tempPdo = null; // Fermer la connexion temporaire
                                                                                                                                               
                                                                                                                                                           // Connexion à la base de données
                                                                                                                                                                       $dsn = "mysql:host=" . DB_HOST . ";dbname=" . DB_NAME . ";charset=" . DB_CHARSET;
                                                                                                                                                                                   $pdo = new PDO($dsn, DB_USER, DB_PASS, $GLOBALS['options']);
                                                                                                                                                                                               
                                                                                                                                                                                                           // Vérifier si les tables existent
                                                                                                                                                                                                                       $stmt = $pdo->query("SHOW TABLES LIKE 'utilisateurs'");
                                                                                                                                                                                                                                   if ($stmt->rowCount() === 0) {
                                                                                                                                                                                                                                                   // Les tables n'existent pas - importer database.sql
                                                                                                                                                                                                                                                                   importDatabase($pdo);
                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                   } catch (PDOException $e) {
                                                                                                                                                                                                                                                                                                               error_log("Erreur connexion DB: " . $e->getMessage());
                                                                                                                                                                                                                                                                                                                           die("
                                                                                                                                                                                                                                                                                                                                           <div style='font-family:Segoe UI;padding:40px;text-align:center;'>
                                                                                                                                                                                                                                                                                                                                                               <h2 style='color:#d32f2f;'>❌ Erreur de connexion à la base de données</h2>
                                                                                                                                                                                                                                                                                                                                                                                   <p style='font-size:16px;color:#666;'>
                                                                                                                                                                                                                                                                                                                                                                                                           Vérifiez que:<br><br>
                                                                                                                                                                                                                                                                                                                                                                                                                                   1. XAMPP est démarré (Apache + MySQL)<br>
                                                                                                                                                                                                                                                                                                                                                                                                                                                           2. MySQL tourne sur le port 3306<br>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   3. Le mot de passe root est correct<br><br>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           <strong>Erreur:</strong> " . htmlspecialchars($e->getMessage()) . "<br><br>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   <a href='http://localhost/phpmyadmin' target='_blank' style='color:#1a5f2a;'>Ouvrir PHPMyAdmin</a>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   ");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       return $pdo;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       /**
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        * Importer la structure de la base de données
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         function importDatabase(PDO $pdo): void {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             $sqlFile = __DIR__ . '/../database.sql';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (!file_exists($sqlFile)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             error_log("Fichier database.sql non trouvé: " . $sqlFile);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         $sql = file_get_contents($sqlFile);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // Supprimer les commentaires et exécuter les requêtes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 $lines = explode("\n", $sql);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         $query = '';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         foreach ($lines as $line) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     $line = trim($line);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // Ignorer les commentaires et lignes vides
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         if (empty($line) || strpos($line, '--') === 0 || strpos($line, '/*') === 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         continue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             $query .= $line . "\n";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     // Exécuter si la requête se termine par ;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 if (substr($line, -1) === ';') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     $pdo->exec($query);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     } catch (PDOException $e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         // Ignorer les erreurs de "déjà existe"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             if (strpos($e->getMessage(), 'already exists') === false && 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     strpos($e->getMessage(), 'Duplicate') === false) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             error_log("Erreur import SQL: " . $e->getMessage());
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 $query = '';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     error_log("Base de données importée avec succès");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 } catch (Exception $e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         error_log("Erreur lecture database.sql: " . $e->getMessage());
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             /**
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              * Fonction utilitaire: Logger une activité
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               function logActivity(string $action, string $table = null, int $recordId = null, string $details = null): void {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   $db = getDB();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       $userId = $_SESSION['user_id'] ?? null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           $ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           $stmt = $db->prepare("
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       INSERT INTO journal_activites (utilisateur_id, action, table_concernee, enregistrement_id, details, adresse_ip)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   VALUES (:user_id, :action, :table, :record_id, :details, :ip)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           ");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           $stmt->execute([
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       ':user_id'    => $userId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   ':action'     => $action,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               ':table'      => $table,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           ':record_id'  => $recordId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       ':details'    => $details,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   ':ip'         => $ip
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           ]);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               } catch (PDOException $e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       error_log("Erreur log: " . $e->getMessage());
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           